                setUserLocation({
                    lat: latitude,
                    lng: longitude,
                    address: "Your Location"
                });
                setFilters(prev => ({ ...prev, location: '' }));

                // Track GPS location usage
                trackLocationUsage('gps');

                setLoadingLocation(false); // Stop Loading
            };

            const errorCallback = (error, isRetry = false) => {
                console.error(`Γ¥î Geolocation error (${isRetry ? 'Low' : 'High'} Accuracy):`, error.code, error.message);

                // If High Accuracy failed, try Low Accuracy once
                if (!isRetry) {

                    navigator.geolocation.getCurrentPosition(
                        successCallback,
                        (finalError) => errorCallback(finalError, true),
                        { enableHighAccuracy: false, timeout: 10000, maximumAge: 300000 }
                    );
                    return;
                }

                // Final Failure Handling
                setLoadingLocation(false); // Stop Loading on Error
                let errorMessage = "Unable to get your location.\n\n";
                switch (error.code) {
                    case error.PERMISSION_DENIED:
                        errorMessage += "Γ¥î Location permission denied.\n\nPlease:\n1. Click the location icon in your browser's address bar\n2. Allow location access\n3. Try again";
                        console.error("User denied location permission");
                        break;
                    case error.POSITION_UNAVAILABLE:
                        errorMessage += "≡ƒôì Location unavailable.\n\nPlease use 'Select on Map' instead.";
                        console.error("Position unavailable");
                        break;
                    case error.TIMEOUT:
                        errorMessage += "ΓÅ▒∩╕Å Request timed out.\n\nPlease:\n1. Check your GPS/location services\n2. Try 'Select on Map' instead";
                        console.error("Geolocation timeout");
                        break;
                    default:
                        errorMessage += "Please use 'Select on Map' to choose your location.";
                        console.error("Unknown geolocation error:", error);
                }
                alert(errorMessage);
            };

            // 1. Try High Accuracy first
            console.log("≡ƒôì Attempting high accuracy GPS...");
            navigator.geolocation.getCurrentPosition(
                successCallback,
                (err) => errorCallback(err, false),
                { enableHighAccuracy: true, timeout: 10000, maximumAge: 60000 }
            );

        } else {
            console.error("Γ¥î Geolocation not supported by browser");
            setLoadingLocation(false);
            alert("Your browser doesn't support location services.\n\nPlease use 'Select on Map' instead.");
        }
    };

    // Auto-detect location on load (optional, better UX to ask first or just button)
    // useEffect(() => { handleLocationSelect(); }, []);

    useEffect(() => {
        // Fetch Messes
