                                            <span className="text-slate-500 text-[10px] font-mono">#{room.id.slice(-6)}</span>
                                        </div>

                                        <h3 className="text-lg font-bold text-white mb-1 group-hover:text-cyan-400 transition-colors">
                                            {room.messName}
                                        </h3>
                                        <p className="text-slate-400 text-xs mb-4 flex items-center gap-1.5 min-h-[16px]">
                                            {room.category && <><Layout size={12} className="opacity-50" /> {room.category}</>}
                                        </p>

                                        <div className="bg-slate-900/50 rounded-xl p-4 mb-5 border border-slate-700/50 flex-grow">
                                            <div className="flex justify-between items-center mb-2">
                                                <span className="text-xs text-slate-500 uppercase font-black">Price</span>
                                                <span className="text-emerald-400 font-bold">Γé╣{room.price}/mo</span>
                                            </div>
                                            <div className="flex justify-between items-center">
                                                <span className="text-xs text-slate-500 uppercase font-black">Availability</span>
                                                <span className="text-white font-bold">{room.availableCount} {room.occupancy === 'Single' ? 'Bed' : 'Seats'}</span>
                                            </div>
                                        </div>

                                        <div className="flex gap-2 mt-auto">
                                            <button
                                                onClick={() => handleEditItem(room, 'room')}
                                                className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-slate-200 py-2.5 rounded-xl text-xs font-bold transition-all border border-slate-600"
                                            >
                                                <Edit3 size={14} /> Edit
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* HERO ADS TAB */}
                    {activeTab === 'hero_ads' && (
                        <div className="max-w-6xl mx-auto">
                            <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
                                <Image className="text-pink-500" />
                                Hero Ads Management
                            </h2>

                            {/* Global Toggle */}
                            <div className="bg-slate-800 rounded-2xl border border-slate-700 p-6 mb-8 shadow-xl">
                                <div className="flex items-center justify-between">
                                    <div>
                                        <h3 className="text-lg font-bold text-white">Enable Ad Carousel</h3>
                                        <p className="text-slate-400 text-sm mt-1">
                                            {carouselEnabled
                                                ? 'Carousel is LIVE ΓÇö users see ad banners on the home page'
                                                : 'Carousel is OFF ΓÇö users see the default hero section'}
                                        </p>
                                    </div>
                                    <button
                                        onClick={handleToggleCarousel}
                                        className={`flex items-center gap-2 px-5 py-3 rounded-xl font-bold text-sm transition-all shadow-lg ${
                                            carouselEnabled
                                                ? 'bg-emerald-500 text-white hover:bg-emerald-600 shadow-emerald-500/20'
                                                : 'bg-slate-700 text-slate-300 hover:bg-slate-600 border border-slate-600'
                                        }`}
                                    >
                                        {carouselEnabled ? <ToggleRight size={20} /> : <ToggleLeft size={20} />}
                                        {carouselEnabled ? 'ON' : 'OFF'}
                                    </button>
                                </div>
                            </div>

                            {/* Two Sections */}
                            <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                                {/* Desktop Banners */}
                                {[{ section: 'desktop', ads: desktopAds, icon: <Monitor size={20} />, label: 'Desktop Banners', size: '1400 ├ù 500 px', color: 'blue' },
                                  { section: 'mobile', ads: mobileAds, icon: <Smartphone size={20} />, label: 'Mobile Banners', size: '800 ├ù 600 px', color: 'orange' }].map(({ section, ads: sectionAds, icon, label, size, color }) => (
                                    <div key={section} className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden shadow-xl">
                                        {/* Section Header */}
                                        <div className={`p-5 border-b border-slate-700 bg-${color}-500/5`}>
                                            <div className="flex items-center justify-between">
                                                <div className="flex items-center gap-3">
                                                    <div className={`p-2 rounded-lg bg-${color}-500/10 text-${color}-400`}>
                                                        {icon}
                                                    </div>
                                                    <div>
                                                        <h3 className="font-bold text-white text-lg">{label}</h3>
                                                        <p className="text-slate-500 text-xs">Recommended: {size}</p>
                                                    </div>
                                                </div>
                                                <span className={`px-3 py-1 rounded-lg text-sm font-bold ${
                                                    sectionAds.length >= 10
                                                        ? 'bg-red-500/20 text-red-400 border border-red-500/30'
                                                        : 'bg-slate-700 text-slate-300'
                                                }`}>
                                                    {sectionAds.length}/10
                                                </span>
                                            </div>
                                        </div>

                                        {/* Upload Form */}
                                        <div className="p-5 border-b border-slate-700">
                                            <div className="space-y-3">
                                                <div>
                                                    <input
                                                        id={`hero-ad-file-${section}`}
                                                        type="file"
                                                        accept="image/*"
                                                        disabled={sectionAds.length >= 10 || heroAdUploading}
                                                        onChange={(e) => setHeroAdFile(e.target.files?.[0] || null)}
                                                        className="w-full text-sm text-slate-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-bold file:bg-pink-500/10 file:text-pink-400 hover:file:bg-pink-500/20 disabled:opacity-40"
                                                    />
                                                </div>
                                                <div className="grid grid-cols-2 gap-3">
                                                    <input
                                                        type="text"
                                                        placeholder="Link URL (optional)"
                                                        value={heroAdForm.linkUrl}
                                                        onChange={(e) => setHeroAdForm({ ...heroAdForm, linkUrl: e.target.value })}
                                                        className="px-3 py-2 bg-slate-900 border border-slate-700 rounded-xl text-sm text-white focus:ring-1 focus:ring-pink-500 outline-none"
                                                    />
                                                    <input
                                                        type="text"
                                                        placeholder="Title (optional)"
                                                        value={heroAdForm.title}
                                                        onChange={(e) => setHeroAdForm({ ...heroAdForm, title: e.target.value })}
                                                        className="px-3 py-2 bg-slate-900 border border-slate-700 rounded-xl text-sm text-white focus:ring-1 focus:ring-pink-500 outline-none"
                                                    />
                                                </div>
                                                <button
                                                    onClick={() => handleHeroAdUpload(section)}
                                                    disabled={!heroAdFile || heroAdUploading || sectionAds.length >= 10}
                                                    className="w-full py-2.5 bg-pink-500 hover:bg-pink-600 text-white font-bold rounded-xl text-sm transition-all disabled:opacity-40 disabled:cursor-not-allowed shadow-lg shadow-pink-500/10"
                                                >
                                                    {heroAdUploading ? 'Uploading...' : sectionAds.length >= 10 ? 'Limit Reached (10/10)' : 'Upload Banner'}
                                                </button>
                                            </div>
                                        </div>

                                        {/* Banner List */}
                                        <div className="p-5 space-y-3 max-h-[600px] overflow-y-auto">
                                            {sectionAds.length === 0 ? (
                                                <div className="text-center py-12 text-slate-500 text-sm">
                                                    No banners uploaded yet.
                                                </div>
                                            ) : (
                                                sectionAds.map((ad, idx) => (
                                                    <div key={ad.id} className={`bg-slate-900/50 rounded-xl border ${ad.active ? 'border-slate-700' : 'border-slate-700/50 opacity-50'} p-3 flex gap-3 items-center group`}>
                                                        {/* Thumbnail */}
                                                        <img
                                                            src={ad.imageUrl}
                                                            alt={ad.title || 'Banner'}
                                                            className="w-24 h-16 object-cover rounded-lg shrink-0 border border-slate-700"
                                                        />

                                                        {/* Info */}
                                                        <div className="flex-1 min-w-0">
                                                            <p className="text-white text-sm font-bold truncate">{ad.title || 'Untitled'}</p>
                                                            {ad.linkUrl && <p className="text-slate-500 text-xs truncate">{ad.linkUrl}</p>}
                                                            <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold mt-1 inline-block ${ad.active ? 'bg-emerald-500/20 text-emerald-400' : 'bg-slate-700 text-slate-500'}`}>
                                                                {ad.active ? 'ACTIVE' : 'HIDDEN'}
                                                            </span>
                                                        </div>

                                                        {/* Actions */}
                                                        <div className="flex items-center gap-1 shrink-0">
                                                            <button
                                                                onClick={() => handleReorderHeroAd(ad.id, 'up', section)}
                                                                disabled={idx === 0}
                                                                className="p-1.5 text-slate-500 hover:text-white hover:bg-slate-700 rounded-lg transition-colors disabled:opacity-20"
                                                                title="Move up"
                                                            >
                                                                <ArrowUp size={14} />
                                                            </button>
                                                            <button
                                                                onClick={() => handleReorderHeroAd(ad.id, 'down', section)}
                                                                disabled={idx === sectionAds.length - 1}
                                                                className="p-1.5 text-slate-500 hover:text-white hover:bg-slate-700 rounded-lg transition-colors disabled:opacity-20"
                                                                title="Move down"
                                                            >
                                                                <ArrowDown size={14} />
                                                            </button>
                                                            <button
                                                                onClick={() => handleToggleHeroAd(ad.id, ad.active, section)}
                                                                className={`p-1.5 rounded-lg transition-colors ${ad.active ? 'text-emerald-400 hover:bg-emerald-500/20' : 'text-slate-500 hover:bg-slate-700'}`}
                                                                title={ad.active ? 'Hide' : 'Show'}
                                                            >
                                                                {ad.active ? <Eye size={14} /> : <EyeOff size={14} />}
                                                            </button>
                                                            <button
                                                                onClick={() => handleDeleteHeroAd(ad.id, section)}
                                                                className="p-1.5 text-slate-500 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-colors"
                                                                title="Delete"
                                                            >
                                                                <Trash2 size={14} />
                                                            </button>
                                                        </div>
                                                    </div>
                                                ))
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                </main>
            </div>

            {/* EDIT MODAL */}
            {editingItem && editForm && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm animate-in fade-in duration-200">
                    <div className="bg-slate-800 w-full max-w-2xl max-h-[90vh] overflow-y-auto rounded-3xl shadow-2xl border border-slate-700 animate-in zoom-in-95 duration-200">
                        <div className="sticky top-0 bg-slate-800 p-6 border-b border-slate-700 flex justify-between items-center z-10">
                            <h2 className="text-xl font-bold flex items-center gap-2">
                                <Edit3 size={20} className="text-indigo-400" />
                                Edit {editingItem.type === 'mess' ? 'Mess Profile' : 'Room Type'}
                            </h2>
                            <button
                                onClick={() => { setEditingItem(null); setEditForm(null); }}
                                className="p-2 hover:bg-slate-700 rounded-full transition-colors"
                            >
                                <XCircle size={24} className="text-slate-400" />
                            </button>
                        </div>

                        <form onSubmit={handleEditSubmit} className="p-6 space-y-6">
                            {editingItem.type === 'mess' ? (
                                <>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Mess Name</label>
                                            <input
                                                type="text"
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-indigo-500"
                                                value={editForm.name}
                                                onChange={e => setEditForm({ ...editForm, name: e.target.value })}
                                                required
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Type</label>
                                            <select
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-indigo-500"
                                                value={editForm.messType}
                                                onChange={e => setEditForm({ ...editForm, messType: e.target.value })}
                                            >
                                                <option value="Boys">Boys Mess</option>
                                                <option value="Girls">Girls Mess</option>
                                                <option value="Co-ed">Co-ed Mess</option>
                                            </select>
                                        </div>
                                    </div>

                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Address</label>
                                        <textarea
                                            className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-indigo-500 h-20 resize-none"
                                            value={editForm.address}
                                            onChange={e => setEditForm({ ...editForm, address: e.target.value })}
                                            required
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Description / About Mess</label>
                                        <textarea
                                            className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-indigo-500 h-32 resize-none"
                                            value={editForm.description || ''}
                                            onChange={e => setEditForm({ ...editForm, description: e.target.value })}
                                            placeholder=" detailed description about the mess, facilities, rules etc."
                                        />
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Contact</label>
                                            <input
                                                type="text"
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-indigo-500"
                                                value={editForm.contact}
                                                onChange={e => setEditForm({ ...editForm, contact: e.target.value })}
                                                required
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Maps URL</label>
                                            <input
                                                type="text"
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-indigo-500"
                                                value={editForm.locationUrl}
                                                onChange={e => setEditForm({ ...editForm, locationUrl: e.target.value })}
                                            />
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Price Policy / Deposit</label>
                                            <input
                                                type="text"
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-indigo-500"
                                                value={editForm.advanceDeposit}
                                                onChange={e => setEditForm({ ...editForm, advanceDeposit: e.target.value })}
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Security/Other Details</label>
                                            <input
                                                type="text"
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-indigo-500"
                                                value={editForm.security}
                                                onChange={e => setEditForm({ ...editForm, security: e.target.value })}
                                            />
                                        </div>
                                    </div>

                                    <div>
                                        <MultiSelectDropdown
                                            label="Mess Amenities"
                                            options={[
                                                { key: 'food', label: 'Food' },
                                                { key: 'wifi', label: 'WiFi' },
                                                { key: 'inverter', label: 'Electricity Backup' }
                                            ]}
                                            selected={editForm.amenities}
                                            onChange={(key, checked) => setEditForm({
                                                ...editForm,
                                                amenities: { ...editForm.amenities, [key]: checked }
                                            })}
                                            color="indigo"
                                        />
                                    </div>

                                    <div className="p-4 bg-slate-900/50 rounded-2xl border border-slate-700 flex flex-col gap-4">
                                        <label className="flex items-center gap-3 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                className="w-5 h-5 accent-indigo-500"
                                                checked={editForm.hidden}
                                                onChange={e => setEditForm({ ...editForm, hidden: e.target.checked })}
                                            />
                                            <div>
                                                <span className="text-sm font-bold text-white">Private Listing</span>
                                                <p className="text-[10px] text-slate-500">Hide this mess from the public home page</p>
                                            </div>
                                        </label>

                                        <label className="flex items-center gap-3 cursor-pointer border-t border-slate-700/50 pt-3">
                                            <input
                                                type="checkbox"
                                                className="w-5 h-5 accent-indigo-500"
                                                checked={editForm.hideContact}
                                                onChange={e => setEditForm({ ...editForm, hideContact: e.target.checked })}
                                            />
                                            <div>
                                                <span className="text-sm font-bold text-white">Hide Contact Number</span>
                                                <p className="text-[10px] text-slate-500">Show "Not Available" instead of phone number</p>
                                            </div>
                                        </label>
                                    </div>

                                    <div className="p-4 bg-slate-900/50 rounded-2xl border border-slate-700">
                                        <div className="flex items-center gap-3 mb-4">
                                            <input
                                                type="checkbox"
                                                className="w-5 h-5 accent-amber-500"
                                                checked={editForm.isUserSourced}
                                                onChange={e => setEditForm({ ...editForm, isUserSourced: e.target.checked })}
                                            />
                                            <span className="text-sm font-bold text-white">Managed (User Sourced)</span>
                                        </div>
                                        {editForm.isUserSourced && (
                                            <div>
                                                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Last Update Date</label>
                                                <input
                                                    type="date"
                                                    className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-amber-500"
                                                    value={editForm.lastUpdatedDate}
                                                    onChange={e => setEditForm({ ...editForm, lastUpdatedDate: e.target.value })}
                                                    required
                                                />
                                            </div>
                                        )}
                                    </div>

                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Poster Image</label>
                                        <input
                                            type="file"
                                            className="w-full text-sm text-slate-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-bold file:bg-indigo-500/10 file:text-indigo-400 hover:file:bg-indigo-500/20"
                                            onChange={e => setEditImageFiles(e.target.files)}
                                            accept="image/*"
                                        />
                                    </div>

                                    <div className="pt-2 border-t border-slate-700">
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-2 flex items-center gap-2">
                                            Mess Photo Gallery (Max 15)
                                        </label>
                                        <input
                                            type="file"
                                            multiple
                                            accept="image/*"
                                            onChange={(e) => setEditGalleryFiles(e.target.files)}
                                            className="w-full text-sm text-slate-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-bold file:bg-purple-500/10 file:text-purple-400 hover:file:bg-purple-500/20"
                                        />

                                        {editForm.galleryUrls?.length > 0 && (
                                            <div className="mt-4">
                                                <p className="text-xs text-slate-500 mb-2 font-medium">Current Gallery ({editForm.galleryUrls.length}/15):</p>
                                                <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-3">
                                                    {editForm.galleryUrls.map((url, idx) => (
                                                        <div key={idx} className="relative group rounded-md overflow-hidden border border-slate-700 shadow-sm aspect-square bg-slate-900">
                                                            <img src={url} alt={`Gallery ${idx + 1}`} className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
                                                            <button
                                                                type="button"
                                                                onClick={(e) => { e.preventDefault(); removeGalleryImage(url); }}
                                                                className="absolute top-1 right-1 bg-red-500/80 hover:bg-red-600 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                                                                title="Remove Image"
                                                            >
                                                                <Trash2 size={12} />
                                                            </button>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </>
                            ) : (
                                <>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Occupancy</label>
                                            <select
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-cyan-500"
                                                value={editForm.occupancy}
                                                onChange={e => setEditForm({ ...editForm, occupancy: e.target.value })}
                                            >
                                                <option value="Single">Single</option>
                                                <option value="Double">Double</option>
                                                <option value="Triple">Triple</option>
                                                <option value="Four">Four</option>
                                                <option value="Five">Five</option>
                                                <option value="Six">Six</option>
                                            </select>
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Price (Γé╣/mo)</label>
                                            <input
                                                type="number"
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-cyan-500"
                                                value={editForm.price}
                                                onChange={e => setEditForm({ ...editForm, price: e.target.value })}
                                                required
                                            />
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Total Inventory</label>
                                            <input
                                                type="number"
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-cyan-500"
                                                value={editForm.totalInventory}
                                                onChange={e => setEditForm({ ...editForm, totalInventory: e.target.value })}
                                                required
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Available Seats/Beds</label>
                                            <input
                                                type="number"
                                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-cyan-500"
                                                value={editForm.availableCount}
                                                onChange={e => setEditForm({ ...editForm, availableCount: e.target.value })}
                                                required
                                            />
                                        </div>
                                    </div>

                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Category / Other Info</label>
                                        <textarea
                                            placeholder="e.g. Deluxe AC, includes study table"
                                            className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white outline-none focus:ring-2 focus:ring-cyan-500 h-20 resize-none"
                                            value={editForm.category}
                                            onChange={e => setEditForm({ ...editForm, category: e.target.value })}
                                        />
                                    </div>

                                    <div>
                                        <MultiSelectDropdown
                                            label="Room Amenities"
                                            options={[
                                                { key: 'ac', label: 'AC' },
                                                { key: 'attachedBathroom', label: 'Attached Bathroom' }
                                            ]}
                                            selected={editForm.amenities}
                                            onChange={(key, checked) => setEditForm({
                                                ...editForm,
                                                amenities: { ...editForm.amenities, [key]: checked }
                                            })}
                                            color="cyan"
                                        />
                                    </div>
                                </>
                            )}

                            <div className="pt-4 flex gap-3">
                                <button
                                    type="submit"
                                    disabled={isSaving}
                                    className="flex-1 bg-indigo-500 hover:bg-indigo-600 disabled:bg-indigo-500/50 text-white font-bold py-3 rounded-2xl transition-all shadow-lg shadow-indigo-500/20 active:scale-95 flex items-center justify-center gap-2"
                                >
                                    {isSaving ? 'Saving Changes...' : 'Save Changes'}
                                </button>
                                <button
                                    type="button"
                                    onClick={() => { setEditingItem(null); setEditForm(null); }}
                                    className="px-6 bg-slate-700 hover:bg-slate-600 text-slate-300 font-bold py-3 rounded-2xl transition-all border border-slate-600"
                                >
                                    Cancel
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}


        </div >
    );
};

export default OperationalDashboard;

import React, { useState } from 'react';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword } from 'firebase/auth';
import { auth } from '../firebase';
import { useNavigate } from 'react-router-dom';
import { ShieldCheck, Server, Eye, EyeOff } from 'lucide-react';

const OperationalLogin = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const ALLOWED_OPERATOR_EMAIL = import.meta.env.VITE_OP_EMAIL;

    const handleLogin = async (e) => {
        e.preventDefault();
        setError('');

        if (!ALLOWED_OPERATOR_EMAIL) {
            setError("Configuration Error: No Operator Email set in environment.");
            return;
        }

        if (email !== ALLOWED_OPERATOR_EMAIL) {
            setError("Access Denied: You are not authorized to access this interface.");
            return;
        }

        try {
            await signInWithEmailAndPassword(auth, email, password);
            navigate('/operational/dashboard');
        } catch (err) {
            console.error("Login Error:", err);
            setError("Invalid credentials or server error.");
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-900 px-4">
            <div className="bg-slate-800 p-8 rounded-2xl shadow-2xl w-full max-w-md border border-slate-700">
                <div className="text-center mb-8">
                    <div className="bg-emerald-500/10 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-emerald-500">
                        <Server size={32} />
                    </div>
                    <h2 className="text-2xl font-bold text-white">Operational Access</h2>
                    <p className="text-slate-400">Restricted to Authorized Operators Only</p>
                </div>

                {error && (
                    <div className="bg-red-500/10 border border-red-500/20 text-red-500 p-3 rounded-lg mb-4 text-sm text-center">
                        {error}
                    </div>
                )}

                <form onSubmit={handleLogin} className="space-y-6">
                    <div>
                        <label className="block text-sm font-medium text-slate-300 mb-1">Operator Email</label>
                        <input
                            type="email"
                            required
                            className="w-full px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-300 mb-1">Password</label>
                        <div className="relative">
                            <input
                                type={showPassword ? "text" : "password"}
                                required
                                className="w-full px-4 py-2 pr-12 bg-slate-900 border border-slate-700 rounded-lg text-white focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-500 hover:text-slate-300 focus:outline-none"
                            >
                                {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                            </button>
                        </div>
                    </div>
                    <button
                        type="submit"
                        className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-semibold py-3 rounded-lg transition-colors shadow-lg shadow-emerald-900/20"
                    >
                        Authenticate
                    </button>

                </form>

                <div className="mt-6 text-center">
                    <a href="/" className="text-xs text-slate-500 hover:text-slate-400 transition-colors">
                        ΓåÉ Exit to Public Site
                    </a>
                </div>
            </div>
        </div>
    );
};

export default OperationalLogin;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, useSearchParams } from 'react-router-dom';
import { db } from '../firebase';
import { doc, getDoc, collection, addDoc, serverTimestamp, query, where, getDocs } from 'firebase/firestore';
import { useAuth } from '../context/AuthContext';
import { useWishlist } from '../hooks/useWishlist';
import { MapPin, Wifi, Zap, CheckCircle, ArrowLeft, BedDouble, Wind, Droplets, Utensils, Star, Shield, Lock, Bell, Heart, Phone, AlertCircle } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion'; // eslint-disable-line no-unused-vars
import PhoneCollectionModal from '../components/PhoneCollectionModal';
import { trackRoomView, trackBookingInitiated, trackContactOwner, trackAvailabilityInquiry } from '../analytics';

const RoomDetails = () => {
    const { messId, roomId } = useParams();
    const navigate = useNavigate();
    const { currentUser, userRole } = useAuth();

    const [mess, setMess] = useState(null);
    const [room, setRoom] = useState(null);
    const [loading, setLoading] = useState(true);
    const [showConfirmModal, setShowConfirmModal] = useState(false);
    const [showPhoneModal, setShowPhoneModal] = useState(false);
    const [userPhone, setUserPhone] = useState('');
    const [showLoginPrompt, setShowLoginPrompt] = useState(false);
    const [bookingProcessing, setBookingProcessing] = useState(false);
    const { isRoomWishlisted, toggleRoomWishlist } = useWishlist();

    // Notification / Inquiry State
    const [showNotifyModal, setShowNotifyModal] = useState(false);
    const [notifyLoading, setNotifyLoading] = useState(false);
    const [notifyMessage, setNotifyMessage] = useState(""); // User's custom message
    const [notifyPhone, setNotifyPhone] = useState(""); // Phone number for availability inquiry
    const [notifyConsent, setNotifyConsent] = useState(false);


    useEffect(() => {
        const fetchDetails = async () => {
            try {
                // Fetch Mess
                const messDoc = await getDoc(doc(db, "messes", messId));
                if (messDoc.exists()) {
                    setMess({ id: messDoc.id, ...messDoc.data() });
                }

                // Fetch Room
                const roomDoc = await getDoc(doc(db, "rooms", roomId));
                if (roomDoc.exists()) {
                    setRoom({ id: roomDoc.id, ...roomDoc.data() });
                }
            } catch (error) {
                console.error("Error details:", error);
            } finally {
                setLoading(false);
            }
        };

        fetchDetails();
    }, [messId, roomId]);

    // Track room view when component mounts
    useEffect(() => {
        if (mess && room) {
            trackRoomView(roomId, messId, room.price);
        }
    }, [mess, room, messId, roomId]);

    // Disable body scroll when modals are open
    useEffect(() => {
        if (showNotifyModal || showConfirmModal || showPhoneModal) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = 'auto';
        }

        return () => {
            document.body.style.overflow = 'auto';
        };
    }, [showNotifyModal, showConfirmModal, showPhoneModal]);

    const [searchParams, setSearchParams] = useSearchParams();

    useEffect(() => {
        if (!loading && currentUser && searchParams.get('action') === 'book') {
            handleBookClick();
            // Clear the param to prevent re-triggering
            const newParams = new URLSearchParams(searchParams);
            newParams.delete('action');
            setSearchParams(newParams, { replace: true });
        }
    }, [currentUser, loading]);

    const handleBookClick = async () => {
        if (!currentUser) {
            // Redirect to Login with return URL ensuring action=book is preserved
            const returnUrl = `/room/${messId}/${roomId}?action=book`;
            console.log('≡ƒöù Redirecting to login with return URL:', returnUrl);
            navigate(`/user-login?redirect=${encodeURIComponent(returnUrl)}`);
            return;
        }

        // Check if owner contact is available
        if (!mess.contact || mess.hideContact) {
            alert("Owner's contact is currently unavailable for this mess. Please try again later.");
            return;
        }
        if (userRole !== 'user') {
            alert("Partners cannot book rooms. Please login as a User.");
            return;
        }

        // --- ENFORCE DAILY LIMIT ---
        try {
            const bookingsRef = collection(db, "bookings");
            const q = query(
                bookingsRef,
                where("userId", "==", currentUser.uid)
            );

            const querySnapshot = await getDocs(q);
            let todayCount = 0;
            const today = new Date();
            today.setHours(0, 0, 0, 0);

            querySnapshot.forEach((doc) => {
                const data = doc.data();
                if (data.createdAt && data.createdAt.toDate) {
                    const createdAtDate = data.createdAt.toDate();
                    if (createdAtDate >= today) {
                        todayCount++;
                    }
                }
            });

            if (todayCount >= 5) {
                alert("You have reached the maximum limit of 5 call requests per day. Please try again tomorrow.");
                return;
            }
        } catch (error) {
            console.error("Error checking booking limit:", error);
            // Non-blocking fallback if query fails
        }
        // ---------------------------

        // Check if user has a phone number
        const userDoc = await getDoc(doc(db, "users", currentUser.uid));
        const userData = userDoc.exists() ? userDoc.data() : {};
        const phone = userData.phone || '';

        // Track booking initiation (Contact Owner button clicked)
        trackBookingInitiated(roomId, messId, room.price);
        trackContactOwner('button_clicked', messId, roomId);

        if (!phone || phone === 'N/A') {
            // No phone - show phone collection modal
            setShowPhoneModal(true);
        } else {
            // Has phone - proceed to booking confirmation
            setUserPhone(phone);
            setShowConfirmModal(true);
        }
    };

    const handleConfirmBooking = async () => {
        setBookingProcessing(true);
        try {
            const userDoc = await getDoc(doc(db, "users", currentUser.uid));
            const userData = userDoc.exists() ? userDoc.data() : {};

            const bookingData = {
                userId: currentUser.uid,
                userName: userData.name || currentUser.displayName || "User",
                userPhone: userPhone || userData.phone || "N/A",
                messId: mess.id,
                messName: mess.name,
                roomId: room.id,
                roomType: room.occupancy || "Standard",
                price: room.price,
                ownerPhone: mess.contact,
                status: 'contacted',
                createdAt: serverTimestamp()
            };

            await addDoc(collection(db, "bookings"), bookingData);

            // Send Telegram Notification
            import('../utils/telegramNotifier').then(({ sendTelegramNotification, telegramTemplates }) => {
                sendTelegramNotification(telegramTemplates.newBooking(bookingData));
            });
            setShowConfirmModal(false);

            // Open the phone dialer with the owner's contact number
            trackContactOwner('call_confirmed', messId, roomId);
            window.location.href = `tel:${mess.contact}`;
        } catch (error) {
            console.error("Contact owner failed:", error);
            alert("Something went wrong. Please try again.");
        } finally {
            setBookingProcessing(false);
        }
    };

    const handleNotifySubmit = async (e) => {
        e.preventDefault();

        // Validate phone number
        if (!notifyPhone.trim() || notifyPhone.length < 10) {
            alert("Please enter a valid phone number.");
            return;
        }

        setNotifyLoading(true);

        try {
            let userData = {};
            if (currentUser?.uid) {
                const userDoc = await getDoc(doc(db, "users", currentUser.uid));
                userData = userDoc.exists() ? userDoc.data() : {};
            }

            const inquiryData = {
                messId: mess.id,
                messName: mess.name,
                roomId: room.id,
                roomType: room.occupancy,
                name: userData.name || currentUser?.displayName || "Interested User",
                email: currentUser?.email || null,
                phone: notifyPhone,
                message: `I am interested in knowing the seat availability for the sold-out ${room.occupancy} Seater room. ${notifyMessage}`,
                createdAt: serverTimestamp(),
                status: 'pending',
                type: 'availability_request'
            };

            await addDoc(collection(db, "inquiries"), inquiryData);

            // Track the availability inquiry
            trackAvailabilityInquiry(mess.id, room.id);

            // Send Telegram Notification
            import('../utils/telegramNotifier').then(({ sendTelegramNotification, telegramTemplates }) => {
                sendTelegramNotification(telegramTemplates.newInquiry(inquiryData));
            });

            alert("Request sent! The owner will contact you if seats become available.");
            setShowNotifyModal(false);
            setNotifyMessage("");
            setNotifyPhone("");
        } catch (error) {
            console.error("Error sending inquiry:", error);
            alert("Failed to send request. Please try again.");
        } finally {
            setNotifyLoading(false);
        }
    };

    const handleRoomWishlistClick = (e) => {
        e.preventDefault();
        e.stopPropagation();
        if (!currentUser) {
            setShowLoginPrompt(true);
            return;
        }
        toggleRoomWishlist(roomId);
    };

    if (loading) return <div className="p-10 text-center">Loading details...</div>;
    if (!mess || !room) return <div className="p-10 text-center">Details not found.</div>;

    return (
        <div className="min-h-screen bg-brand-secondary pb-20">
            {/* Login Prompt Modal - slides down from top */}
            {showLoginPrompt && (
                <div className="fixed inset-0 z-[200] flex flex-col items-center pointer-events-none">
                    <div
                        className="absolute inset-0 bg-black/40 backdrop-blur-sm pointer-events-auto"
                        onClick={() => setShowLoginPrompt(false)}
                    />
                    <div className="relative pointer-events-auto w-full max-w-sm mt-20 mx-4 bg-white rounded-3xl shadow-2xl p-6">
                        <div className="flex flex-col items-center text-center gap-3">
                            <div className="w-14 h-14 rounded-full bg-red-50 flex items-center justify-center text-2xl">Γ¥ñ∩╕Å</div>
                            <h3 className="text-lg font-bold text-brand-text-dark">Save to Wishlist</h3>
                            <p className="text-sm text-brand-text-gray">Login to save messes and rooms to your personal wishlist.</p>
                            <button
                                onClick={() => { setShowLoginPrompt(false); navigate('/user-login'); }}
                                className="w-full py-3 bg-brand-primary text-white font-bold rounded-xl hover:bg-brand-primary-hover transition-colors shadow-lg shadow-brand-primary/20"
                            >
                                Login / Sign Up
                            </button>
                            <button
                                onClick={() => setShowLoginPrompt(false)}
                                className="text-sm text-brand-text-gray hover:text-brand-text-dark transition-colors"
                            >
                                Maybe later
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Header / Nav */}
            <div className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-brand-light-gray px-4 py-3 flex items-center gap-4">
                <button onClick={() => navigate(-1)} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                    <ArrowLeft size={20} className="text-brand-text-dark" />
                </button>
                <h1 className="text-lg font-bold text-brand-text-dark truncate">Room Details</h1>
            </div>

            <div className="max-w-4xl mx-auto p-4 md:p-6 space-y-6">

                {/* Image Gallery */}
                <div className="bg-white rounded-2xl p-2 shadow-sm border border-brand-light-gray overflow-hidden">
                    {room.imageUrls && room.imageUrls.length > 0 ? (
                        <div className="grid grid-cols-2 gap-2">
                            <img
                                src={room.imageUrls[0]}
                                alt="Room Main"
                                className="w-full h-64 object-cover rounded-xl col-span-2 cursor-pointer hover:opacity-95 transition-opacity"
                                onClick={() => window.open(room.imageUrls[0], '_blank')}
                            />
                            {room.imageUrls.slice(1, 3).map((url, idx) => (
                                <img
                                    key={idx}
                                    src={url}
                                    alt={`Room ${idx + 1}`}
                                    className="w-full h-32 object-cover rounded-xl cursor-pointer hover:opacity-95 transition-opacity"
                                    onClick={() => window.open(url, '_blank')}
                                />
                            ))}
                        </div>
                    ) : (
                        <img
                            src={room.imageUrl || "/default-room.jpg"}
                            alt="Room"
                            className="w-full h-64 object-cover rounded-xl cursor-pointer hover:opacity-95 transition-opacity"
                            onClick={() => window.open(room.imageUrl || "/default-room.jpg", '_blank')}
                        />
                    )}
                </div>

                {/* Title & Price */}
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-brand-light-gray flex flex-col md:flex-row justify-between md:items-start gap-4">
                    <div>
                        <div className="flex items-center gap-3 mb-2">
                            <h2 className="text-2xl font-bold text-brand-text-dark">{({
                                'Single': '1',
                                'Double': '2',
                                'Triple': '3',
                                'Four': '4',
                                'Five': '5',
                                'Six': '6'
                            })[room.occupancy] || room.occupancy} Seater</h2>
                            <span className="bg-brand-accent-green/10 text-brand-accent-green text-xs font-bold px-2 py-0.5 rounded-full border border-brand-accent-green/20">
                                {room.category || 'Standard'}
                            </span>
                            <button
                                onClick={handleRoomWishlistClick}
                                className={`p-1.5 ml-1 rounded-full transition-all flex border shadow-sm shrink-0 items-center justify-center ${isRoomWishlisted(roomId) ? 'bg-red-50 border-red-200' : 'bg-gray-50 border-gray-200 hover:bg-gray-100'}`}
                                title={isRoomWishlisted(roomId) ? "Remove from wishlist" : "Add to wishlist"}
                            >
                                <Heart size={20} className={`transition-all ${isRoomWishlisted(roomId) ? 'fill-red-500 text-red-500 scale-110' : 'text-gray-400 fill-transparent'}`} />
                            </button>
                        </div>
                        <div className="flex items-center gap-2 text-brand-text-gray">
                            <MapPin size={16} className="text-brand-primary" />
                            <span className="font-medium text-brand-primary">{mess.name}</span>
                        </div>
                    </div>
                    <div className="text-left md:text-right">
                        <div className="text-3xl font-black text-brand-text-dark">Γé╣{room.price}<span className="text-sm font-medium text-gray-400">/mo</span></div>
                        <p className="text-xs text-green-600 font-bold bg-green-50 inline-block px-2 py-1 rounded mt-1">
                            {room.availableCount > 0 ? `${room.availableCount} Beds Available` : 'Sold Out'}
                        </p>
                    </div>
                </div>

                {/* Amenities */}
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-brand-light-gray">
                    <h3 className="text-lg font-bold text-brand-text-dark mb-4">Amenities</h3>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {room.amenities?.ac && (
                            <div className="flex flex-col items-center justify-center p-4 bg-blue-50 text-blue-600 rounded-xl border border-blue-100">
                                <Wind size={24} className="mb-2" />
                                <span className="text-sm font-bold">AC</span>
                            </div>
                        )}
                        {room.amenities?.attachedBathroom && (
                            <div className="flex flex-col items-center justify-center p-4 bg-cyan-50 text-cyan-600 rounded-xl border border-cyan-100">
                                <Droplets size={24} className="mb-2" />
                                <span className="text-sm font-bold">Bathroom</span>
                            </div>
                        )}
                        {mess.amenities?.wifi && (
                            <div className="flex flex-col items-center justify-center p-4 bg-indigo-50 text-indigo-600 rounded-xl border border-indigo-100">
                                <Wifi size={24} className="mb-2" />
                                <span className="text-sm font-bold">Wi-Fi</span>
                            </div>
                        )}
                        {mess.amenities?.food && (
                            <div className="flex flex-col items-center justify-center p-4 bg-orange-50 text-orange-600 rounded-xl border border-orange-100">
                                <Utensils size={24} className="mb-2" />
                                <span className="text-sm font-bold">Food</span>
                            </div>
                        )}
                    </div>
                </div>

                {/* Description */}
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-brand-light-gray">
                    <h3 className="text-lg font-bold text-brand-text-dark mb-2">Description</h3>
                    <p className="text-gray-600 leading-relaxed">
                        {room.otherInfo || "No additional description provided for this room."}
                    </p>

                    <div className="mt-6 pt-6 border-t border-gray-100 grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <h4 className="font-bold text-gray-900 mb-2">Mess Rules</h4>
                            <ul className="list-disc list-inside text-sm text-gray-600 space-y-1">
                                <li>Deposit: {mess.advanceDeposit || 'Contact Owner'}</li>
                                <li>Type: {mess.messType}</li>
                            </ul>
                        </div>
                        <div>
                            <h4 className="font-bold text-gray-900 mb-2">Facilities</h4>
                            <ul className="list-disc list-inside text-sm text-gray-600 space-y-1">
                                <li>{mess.foodFacility || 'Standard Menu'}</li>
                                <li>{mess.extraAppliances || 'No heavy appliances'}</li>
                                <li>{mess.security || 'Standard Security'}</li>
                            </ul>
                        </div>
                    </div>
                </div>
            </div>

            {/* Bottom Action Bar */}
            <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 px-6 md:hidden z-20 flex justify-between items-center shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
                <div>
                    <p className="text-xs text-gray-500 font-bold uppercase">Total Rent</p>
                    <p className="text-2xl font-black text-brand-text-dark">Γé╣{room.price}</p>
                </div>
                <button
                    onClick={() => room.availableCount > 0 ? handleBookClick() : setShowNotifyModal(true)}
                    className={`px-8 py-3 rounded-xl font-bold text-lg shadow-lg active:scale-95 transition-all text-white ${room.availableCount > 0
                        ? 'bg-brand-primary hover:bg-brand-primary-hover'
                        : 'bg-indigo-500 hover:bg-indigo-600'
                        }`}
                >
                    {room.availableCount > 0 ? 'Contact Owner' : 'Check Availability'}
                </button>
            </div>

            {/* Desktop Action Button (Floating) */}
            <div className="hidden md:block fixed bottom-8 right-8 z-30">
                <button
                    onClick={() => room.availableCount > 0 ? handleBookClick() : setShowNotifyModal(true)}
                    className={`px-10 py-4 rounded-2xl font-bold text-xl shadow-2xl hover:scale-105 transition-all flex items-center gap-3 text-white ${room.availableCount > 0
                        ? 'bg-brand-primary hover:bg-brand-primary-hover'
                        : 'bg-indigo-500 hover:bg-indigo-600'
                        }`}
                >
                    {room.availableCount > 0 ? (
                        <>
                            <span>Contact Owner</span>
                            <div className="w-px h-6 bg-white/20"></div>
                            <span className="font-normal text-white/80">Γé╣{room.price}</span>
                        </>
                    ) : (
                        <>
                            <span>Check Availability</span>
                            <Bell size={20} />
                        </>
                    )}
                </button>
            </div>


            {/* Contact Owner Modal */}
            <AnimatePresence>
                {showConfirmModal && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="absolute inset-0 bg-black/50 backdrop-blur-sm"
                            onClick={() => setShowConfirmModal(false)}
                        />
                        <motion.div
                            initial={{ scale: 0.9, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.9, opacity: 0 }}
                            className="bg-white w-full max-w-sm rounded-3xl p-6 relative z-10 shadow-2xl"
                        >
                            <div className="text-center mb-5">
                                <div className="w-16 h-16 bg-green-50 rounded-full flex items-center justify-center mx-auto mb-4 text-green-600">
                                    <Phone size={32} />
                                </div>
                                <h3 className="text-2xl font-bold text-brand-text-dark">Contact Owner</h3>
                                <p className="text-gray-500 mt-2 text-sm">
                                    You are about to call the owner of <strong>{mess.name}</strong>.
                                </p>
                            </div>

                            {/* Polite Instructions */}
                            <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 mb-5">
                                <div className="flex items-start gap-2">
                                    <AlertCircle size={18} className="text-amber-600 mt-0.5 shrink-0" />
                                    <div className="text-sm text-amber-800 space-y-1">
                                        <p className="font-semibold">Please keep in mind:</p>
                                        <ul className="list-disc list-inside text-xs space-y-0.5 text-amber-700">
                                            <li>Introduce yourself politely</li>
                                            <li>Mention you found the mess on <strong>MessKhojo</strong></li>
                                            <li>Be respectful of the owner's time</li>
                                            <li>Ask your queries clearly and patiently</li>
                                        </ul>
                                    </div>
                                </div>
                            </div>

                            <div className="bg-gray-50 rounded-xl p-4 mb-5 space-y-3">
                                <div className="flex justify-between text-sm">
                                    <span className="text-gray-500">Room Type</span>
                                    <span className="font-bold text-gray-900">{({
                                        'Single': '1',
                                        'Double': '2',
                                        'Triple': '3',
                                        'Four': '4',
                                        'Five': '5',
                                        'Six': '6'
                                    })[room.occupancy] || room.occupancy} Seater</span>
                                </div>
                                <div className="flex justify-between text-sm">
                                    <span className="text-gray-500">Price</span>
                                    <span className="font-bold text-gray-900">Γé╣{room.price}/mo</span>
                                </div>
                            </div>

                            <div className="flex gap-3">
                                <button
                                    onClick={() => setShowConfirmModal(false)}
                                    className="flex-1 py-3 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors"
                                >
                                    Cancel
                                </button>
                                <button
                                    onClick={handleConfirmBooking}
                                    disabled={bookingProcessing}
                                    className="flex-1 py-3 bg-green-600 hover:bg-green-700 text-white font-bold rounded-xl transition-colors shadow-lg shadow-green-200 disabled:opacity-70 flex items-center justify-center gap-2"
                                >
                                    <Phone size={18} />
                                    {bookingProcessing ? 'Connecting...' : 'Call Now'}
                                </button>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>

            {/* Availability Inquiry Modal */}
            <AnimatePresence>
                {showNotifyModal && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="absolute inset-0 bg-black/50 backdrop-blur-sm"
                            onClick={() => setShowNotifyModal(false)}
                        />
                        <motion.div
                            initial={{ scale: 0.9, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.9, opacity: 0 }}
                            className="bg-white w-full max-w-sm rounded-3xl p-6 relative z-10 shadow-2xl"
                        >
                            <div className="text-center mb-6">
                                <div className="w-16 h-16 bg-indigo-500/10 rounded-full flex items-center justify-center mx-auto mb-4 text-indigo-500">
                                    <Bell size={32} />
                                </div>
                                <h3 className="text-2xl font-bold text-brand-text-dark">Unavailable?</h3>
                                <p className="text-gray-500 mt-2 text-sm leading-relaxed">
                                    This room is currently sold out. Send a request to know when seats become available.
                                </p>
                            </div>

                            <form onSubmit={handleNotifySubmit} className="space-y-4">
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Phone Number <span className="text-red-500">*</span></label>
                                    <input
                                        type="tel"
                                        value={notifyPhone}
                                        onChange={(e) => setNotifyPhone(e.target.value.replace(/\D/g, '').slice(0, 10))}
                                        placeholder="10 digit mobile number"
                                        required
                                        maxLength="10"
                                        className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Custom Message (Optional)</label>
                                    <textarea
                                        value={notifyMessage}
                                        onChange={(e) => setNotifyMessage(e.target.value)}
                                        placeholder="Any specific requirements?"
                                        className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none h-24"
                                    />
                                </div>

                                <div className="flex items-start gap-3 my-2">
                                    <input
                                        type="checkbox"
                                        id="notify-consent"
                                        checked={notifyConsent}
                                        onChange={(e) => setNotifyConsent(e.target.checked)}
                                        className="w-5 h-5 accent-indigo-500 mt-0.5 cursor-pointer shrink-0"
                                    />
                                    <label htmlFor="notify-consent" className="text-xs text-gray-500 cursor-pointer text-left leading-tight">
                                        I agree to the <a href="/terms-and-conditions" target="_blank" rel="noopener noreferrer" className="text-indigo-500 font-bold hover:underline">Terms & Conditions</a> and <a href="/privacy-policy" target="_blank" rel="noopener noreferrer" className="text-indigo-500 font-bold hover:underline">Privacy Policy</a>.
                                    </label>
                                </div>

                                <div className="flex gap-3 pt-2">
                                    <button
                                        type="button"
                                        onClick={() => setShowNotifyModal(false)}
                                        className="flex-1 py-3 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors"
                                    >
                                        Cancel
                                    </button>
                                    <button
                                        type="submit"
                                        disabled={notifyLoading || !notifyConsent}
                                        className="flex-1 py-3 bg-indigo-500 hover:bg-indigo-600 text-white font-bold rounded-xl transition-colors shadow-lg shadow-indigo-200 disabled:opacity-70 disabled:cursor-not-allowed"
                                    >
                                        {notifyLoading ? 'Sending...' : 'Notify Owner'}
                                    </button>
                                </div>
                            </form>
                        </motion.div>
                    </div>
                )
                }
            </AnimatePresence >

            {/* Phone Collection Modal */}
            {
                showPhoneModal && currentUser && (
                    <PhoneCollectionModal
                        user={currentUser}
                        onClose={(phone) => {
                            setUserPhone(phone);
                            setShowPhoneModal(false);
                            setShowConfirmModal(true); // Proceed to booking confirmation
                        }}
                        onSkip={() => {
                            setShowPhoneModal(false);
                            // Don't proceed to booking without phone
                        }}
                    />
                )
            }
        </div >
    );
};

export default RoomDetails;
